## 2. `route` Function — `/home/user/myapp/node_modules/rwsdk/dist/runtime/lib/router.js`

### Signature (from `.d.ts`):
```ts
export declare function route<Path extends string, T extends RequestInfo = RequestInfo>(
    path: Path,
    handler: RouteHandler<T> | MethodHandlers<T>
): RouteDefinition<NormalizePath<Path>, T>;
```

### Implementation:
```js
export function route(path, handler) {
    let normalizedPath = path;
    if (!normalizedPath.startsWith("/")) {
        normalizedPath = "/" + normalizedPath;
    }
    // Special case: wildcard route "*" should normalize to "/*" (not "/*/")
    // to allow it to match the root path "/"
    if (normalizedPath !== "/*" && !normalizedPath.endsWith("/")) {
        normalizedPath = normalizedPath + "/";
    }
    // Normalize custom method keys to lowercase
    if (isMethodHandlers(handler) && handler.custom) {
        handler = {
            ...handler,
            custom: Object.fromEntries(Object.entries(handler.custom).map(([method, methodHandler]) => [
                method.toLowerCase(),
                methodHandler,
            ])),
        };
    }
    return { path: normalizedPath, handler, __rwPath: normalizedPath };
}
```

### Path pattern types:
- **Static**: `/about`, `/contact`
- **Parameters**: `/users/:id`, `/posts/:postId/edit`
- **Wildcards**: `/files/*`, `/api/*/download`

### Usage examples (from JSDoc):
```ts
// Static route
route("/about", () => <AboutPage />)

// Route with parameters
route("/users/:id", ({ params }) => <UserProfile userId={params.id} />)

// Route with wildcards
route("/files/*", ({ params }) => {
    const filePath = params.$0
    return <FileViewer path={filePath} />
})

// Method-based routing
route("/api/users", {
    get: () => Response.json(users),
    post: ({ request }) => Response.json({ status: "created" }, { status: 201 }),
    delete: () => new Response(null, { status: 204 }),
})

// Route with middleware array
route("/admin", [isAuthenticated, isAdmin, () => <AdminDashboard />])
```

### Catch-all/404 route:
```ts
// Wildcard route "*" normalizes to "/*" and matches root "/"
route("*", () => <NotFoundPage />)
```

