### Implementation:
```js
export function render(Document, routes, options = {}) {
    options = { rscPayload: true, ssr: true, ...options };
    const documentMiddleware = ({ rw }) => {
        rw.Document = Document;
        rw.rscPayload = options.rscPayload ?? true;
        rw.ssr = options.ssr ?? true;
    };
    return [documentMiddleware, ...routes];
}
```

`render` creates a middleware that sets `rw.Document`, `rw.rscPayload`, and `rw.ssr` on the request context, then returns the middleware + routes array. It is spread into `defineApp`:

```ts
defineApp([
    render(Document, [
        route("/", () => <HomePage />),
        route("/about", () => <AboutPage />),
    ]),
])
```

